  8→// ValidationError describes a single validation failure.
  9→type ValidationError struct {
 10→	Field   string `json:"field"`
 11→	Message string `json:"message"`
 12→}
 13→
 14→// Unexported interfaces let the validator access concrete-type metadata without
 15→// widening the public Field interface.
 16→type hasEnumOptions interface{ enumOptions() []EnumOption }
 17→type hasHardBounds interface{ hardBounds() (min, max *float64) }
 18→type hasMaxRadius interface{ maxRadiusKm() float64 }
 19→
 20→// ValidateRequest validates a SearchRequest against the registry.
 21→// All errors are collected (no short-circuit) and returned as a slice.
 22→// A nil/empty slice means the request is valid.
 23→//
 24→// The authenticated flag controls access to RESTRICTED fields: when false,
 25→// any filter on a RESTRICTED-searchability field produces a validation error.
 26→func ValidateRequest(reg *Registry, req SearchRequest, authenticated bool) []ValidationError {
 27→	var errs []ValidationError
 28→
 29→	for _, fi := range req.Filters {
 30→		field, ok := reg.Lookup(fi.Field)
 31→		if !ok {
 32→			errs = append(errs, ValidationError{Field: fi.Field, Message: "unknown field"})
 33→			continue
 34→		}
 35→
 36→		if !IsFieldSearchable(field.Descriptor(), authenticated) {
 37→			errs = append(errs, ValidationError{Field: fi.Field, Message: "field requires authentication"})
 38→			continue
 39→		}
 40→
 41→		switch field.Kind() {
 42→		case KindFullText:
 43→			var f FullTextFilter
 44→			if err := json.Unmarshal(fi.Value, &f); err != nil {
 45→				errs = append(errs, ValidationError{Field: fi.Field,
 46→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 47→				continue
 48→			}
 49→			if len(f.Query) > 512 {
 50→				errs = append(errs, ValidationError{Field: fi.Field,
 51→					Message: "value exceeds maximum length of 512 characters"})
 52→			}
 53→
 54→		case KindSubstring:
 55→			var f SubstringFilter
 56→			if err := json.Unmarshal(fi.Value, &f); err != nil {
 57→				errs = append(errs, ValidationError{Field: fi.Field,
 58→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 59→				continue
 60→			}
 61→			if len(f.Value) > 512 {
 62→				errs = append(errs, ValidationError{Field: fi.Field,
 63→					Message: "value exceeds maximum length of 512 characters"})
 64→			}
 65→
 66→		case KindExactString:
 67→			var f ExactStringFilter
 68→			if err := json.Unmarshal(fi.Value, &f); err != nil {
 69→				errs = append(errs, ValidationError{Field: fi.Field,
 70→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 71→				continue
 72→			}
 73→			if len(f.Value) > 512 {
 74→				errs = append(errs, ValidationError{Field: fi.Field,
 75→					Message: "value exceeds maximum length of 512 characters"})
 76→			}
 77→
 78→		case KindExactNumeric:
 79→			var f ExactNumericFilter
 80→			if err := json.Unmarshal(fi.Value, &f); err != nil {
 81→				errs = append(errs, ValidationError{Field: fi.Field,
 82→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 83→			}
 84→
 85→		case KindNumericRange:
 86→			var f NumericRangeFilter
 87→			if err := json.Unmarshal(fi.Value, &f); err != nil {
 88→				errs = append(errs, ValidationError{Field: fi.Field,
 89→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 90→				continue
 91→			}
 92→			if f.Min == nil && f.Max == nil {
 93→				errs = append(errs, ValidationError{Field: fi.Field,
 94→					Message: "at least one of min or max is required"})
 95→				break
 96→			}
 97→			if hb, ok := field.(hasHardBounds); ok {
 98→				hardMin, hardMax := hb.hardBounds()
 99→				if f.Min != nil && hardMin != nil && *f.Min < *hardMin {
100→					errs = append(errs, ValidationError{Field: fi.Field,
101→						Message: "value out of allowed range"})
102→				}
103→				if f.Max != nil && hardMax != nil && *f.Max > *hardMax {
104→					errs = append(errs, ValidationError{Field: fi.Field,
105→						Message: "value out of allowed range"})
106→				}
107→			}
108→
109→		case KindSingleEnum:
110→			var f SingleEnumFilter
111→			if err := json.Unmarshal(fi.Value, &f); err != nil {
112→				errs = append(errs, ValidationError{Field: fi.Field,
113→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
114→				continue
115→			}
116→			if eo, ok := field.(hasEnumOptions); ok {
117→				opts := eo.enumOptions()
118→				if opts != nil && !containsOption(opts, f.Value) {
119→					errs = append(errs, ValidationError{Field: fi.Field,
120→						Message: fmt.Sprintf("value %q not in allowed options", f.Value)})
121→				}
122→			}
123→
124→		case KindMultiEnum:
125→			var f MultiEnumFilter
126→			if err := json.Unmarshal(fi.Value, &f); err != nil {
127→				errs = append(errs, ValidationError{Field: fi.Field,
128→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
129→				continue
130→			}
131→			if len(f.Values) == 0 {
132→				errs = append(errs, ValidationError{Field: fi.Field,
133→					Message: "at least one value required"})
134→				break
135→			}
136→			if eo, ok := field.(hasEnumOptions); ok {
137→				opts := eo.enumOptions()
138→				if opts != nil {
139→					for _, v := range f.Values {
140→						if !containsOption(opts, v) {
141→							errs = append(errs, ValidationError{Field: fi.Field,
142→								Message: fmt.Sprintf("value %q not in allowed options", v)})
143→						}
144→					}
145→				}
146→			}
147→
148→		case KindGeo:
149→			var f GeoFilterInput
150→			if err := json.Unmarshal(fi.Value, &f); err != nil {
151→				errs = append(errs, ValidationError{Field: fi.Field,
152→					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
153→				continue
154→			}
155→			switch f.Kind {
156→			case GeoFilterKindRadius:
157→				if f.Radius == nil {
158→					errs = append(errs, ValidationError{Field: fi.Field,
159→						Message: "radius filter requires radius object"})
160→				} else {
161→					if f.Radius.RadiusKm <= 0 {
162→						errs = append(errs, ValidationError{Field: fi.Field,
163→							Message: "radius must be positive"})
164→					}
165→					if mr, ok := field.(hasMaxRadius); ok {
166→						if f.Radius.RadiusKm > mr.maxRadiusKm() {
167→							errs = append(errs, ValidationError{Field: fi.Field,
168→								Message: fmt.Sprintf("radius exceeds maximum of %g km", mr.maxRadiusKm())})
169→						}
170→					}
171→				}
172→			case GeoFilterKindBBox:
173→				if f.BBox == nil {
174→					errs = append(errs, ValidationError{Field: fi.Field,
175→						Message: "bbox filter requires bbox object"})
176→				}
177→			default:
178→				errs = append(errs, ValidationError{Field: fi.Field,
179→					Message: fmt.Sprintf("unknown geo filter kind: %q", f.Kind)})
180→			}
181→		}
182→	}
183→
184→	// Pagination checks use sentinel field names.
185→	if req.Limit > MaxLimit {
186→		errs = append(errs, ValidationError{Field: "_limit",
187→			Message: fmt.Sprintf("limit exceeds maximum of %d", MaxLimit)})
188→	}
189→	if req.Offset < 0 {
190→		errs = append(errs, ValidationError{Field: "_offset",
191→			Message: "offset must be non-negative"})
192→	}
193→
194→	// UserLocation validation.
195→	if loc := req.UserLocation; loc != nil {
196→		if loc.Latitude < -90 || loc.Latitude > 90 {
197→			errs = append(errs, ValidationError{Field: "_userLocation",
198→				Message: "latitude must be between -90 and 90"})
199→		}
200→		if loc.Longitude < -180 || loc.Longitude > 180 {
201→			errs = append(errs, ValidationError{Field: "_userLocation",
202→				Message: "longitude must be between -180 and 180"})
203→		}
204→		if loc.State != "" {
205→			if len(loc.State) != 2 || loc.State[0] < 'A' || loc.State[0] > 'Z' || loc.State[1] < 'A' || loc.State[1] > 'Z' {
206→				errs = append(errs, ValidationError{Field: "_userLocation",
207→					Message: "state must be a 2-letter uppercase code"})
208→			}
209→		}
210→	}
211→
212→	// Blend validation.
213→	if req.Blend != nil {
214→		hasNonZero := false
215→		for _, bw := range req.Blend.Weights {
216→			if _, ok := rankingProviderMap[bw.Field]; !ok {
217→				errs = append(errs, ValidationError{Field: "_blend",
218→					Message: fmt.Sprintf("unknown blend field %q", bw.Field)})
219→			}
220→			if bw.Weight < 0 || bw.Weight > 100 {
221→				errs = append(errs, ValidationError{Field: "_blend",
222→					Message: fmt.Sprintf("weight for %q must be 0–100", bw.Field)})
223→			}
224→			if bw.Weight > 0 {
225→				hasNonZero = true
226→			}
227→		}
228→		if !hasNonZero {
229→			errs = append(errs, ValidationError{Field: "_blend",
230→				Message: "at least one blend weight must be greater than 0"})
231→		}
232→	}
233→
234→	// Sort validation.
235→	if req.Sort != nil {
236→		switch req.Sort.Field {
237→		case "distance":
238→			if req.UserLocation == nil {
239→				errs = append(errs, ValidationError{Field: "_sort",
240→					Message: "sort by distance requires userLocation"})
241→			}
242→		case "name":
243→			// Always valid.
244→		case "blend_score":
245→			if req.Blend == nil {
246→				errs = append(errs, ValidationError{Field: "_sort",
247→					Message: "sort by blend_score requires an active ranking blend"})
248→			}
249→		default:
250→			f, ok := reg.Lookup(req.Sort.Field)
251→			if !ok {
252→				errs = append(errs, ValidationError{Field: "_sort",
253→					Message: fmt.Sprintf("unknown sort field %q", req.Sort.Field)})
254→			} else if !f.Descriptor().Sortable {
255→				errs = append(errs, ValidationError{Field: "_sort",
256→					Message: fmt.Sprintf("field %q is not sortable", req.Sort.Field)})
257→			}
258→		}
259→	}
260→
261→	return errs
262→}
263→
264→// containsOption returns true when opts contains an entry with Value == v.
265→func containsOption(opts []EnumOption, v string) bool {
266→	for _, o := range opts {
267→		if o.Value == v {
268→			return true
269→		}
270→	}
271→	return false
272→}
