205→	q := fmt.Sprintf(
206→		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
207→		distanceExpr, myPriceExpr, blendExpr,
208→	)
209→	if len(clauses) > 0 {
210→		q += " WHERE " + strings.Join(clauses, " AND ")
211→	}
212→
213→	if req.Blend != nil && req.Sort == nil {
214→		q += " ORDER BY 10 ASC NULLS LAST"
215→	} else {
216→		orderBy, err := buildOrderBy(reg, req)
217→		if err != nil {
218→			return "", nil, err
219→		}
220→		q += orderBy
221→	}
222→
223→	limit := req.Limit
224→	if limit <= 0 {
225→		limit = DefaultLimit
226→	}
227→	if limit > maxRows {
228→		limit = maxRows
229→	}
230→	q += fmt.Sprintf(" LIMIT $%d", argStart)
231→	args = append(args, limit)
232→
233→	return q, args, nil
